const LOGO_SRC = "data:image/jpeg;base64,";

document.addEventListener('DOMContentLoaded', function() {

  // Inject logo into all img.site-logo elements
  document.querySelectorAll('img.site-logo').forEach(img => img.src = LOGO_SRC);

  // Mobile nav toggle
  const toggle = document.querySelector('.nav-toggle');
  const navLinks = document.querySelector('.nav-links');
  if (toggle && navLinks) {
    toggle.addEventListener('click', () => navLinks.classList.toggle('open'));
    navLinks.querySelectorAll('a').forEach(a => a.addEventListener('click', () => navLinks.classList.remove('open')));
  }

  // Active nav link
  const current = window.location.pathname.split('/').pop() || 'index.html';
  document.querySelectorAll('.nav-links a').forEach(a => {
    const href = a.getAttribute('href');
    if (href === current || (current === '' && href === 'index.html')) a.classList.add('active');
  });

  // Scroll reveal
  const reveals = document.querySelectorAll('.reveal');
  const observer = new IntersectionObserver(entries => {
    entries.forEach((e, i) => {
      if (e.isIntersecting) { setTimeout(() => e.target.classList.add('visible'), i * 80); observer.unobserve(e.target); }
    });
  }, { threshold: 0.1 });
  reveals.forEach(el => observer.observe(el));

  // Form handlers
  document.querySelectorAll('form[data-form]').forEach(form => {
    form.addEventListener('submit', e => {
      e.preventDefault();
      form.innerHTML = '<div class="success-msg">Message Sent! 🔥<small>We will be in touch within 24 hours.</small></div>';
    });
  });

  // Music upload
  const audioUpload = document.getElementById('audioUpload');
  const trackList = document.getElementById('trackList');
  if (audioUpload && trackList) {
    let trackCount = trackList.children.length + 1;
    audioUpload.addEventListener('change', e => {
      Array.from(e.target.files).forEach(file => {
        const div = document.createElement('div');
        div.className = 'track-item';
        const num = String(trackCount).padStart(2,'0');
        const name = file.name.replace(/[.][^/.]+$/, '');
        div.innerHTML = '<span class="track-num">' + num + '</span><div class="track-info"><strong>' + name + '</strong><span>Uploaded 2025</span></div><span class="track-dur">---</span>';
        trackList.appendChild(div);
        trackCount++;
      });
    });
  }

  // Hero video fallback
  const vid = document.getElementById('hero-video');
  const fallback = document.getElementById('heroFallback');
  if (vid && fallback) {
    if (vid.readyState >= 3) { fallback.style.display = 'none'; }
    vid.addEventListener('canplay', () => { fallback.style.display = 'none'; });
  }
});
